Route::post('/contact', function(\Illuminate\Http\Request $request) {
    $request->validate(['name' => ['required','string','max:100'], 'email' => ['required','email'], 'subject' => ['required','string'], 'message' => ['required','string','min:10']]);
    $corps = 'Nouveau message - Academie Numerique' . chr(10) . chr(10) . 'Nom: ' . $request->name . chr(10) . 'Email: ' . $request->email . chr(10) . 'Tel: ' . ($request->phone ?? 'Non renseigne') . chr(10) . 'Sujet: ' . $request->subject . chr(10) . chr(10) . 'Message:' . chr(10) . $request->message;
    try {
        foreach (['Medarddaboua@gmail.com', 'allianceodah@gmail.com'] as $dest) {
            \Illuminate\Support\Facades\Mail::raw($corps, function($mail) use ($request, $dest) {
                $mail->to($dest)->subject('[Academie Numerique] ' . $request->subject . ' - ' . $request->name)->replyTo($request->email, $request->name);
            });
        }
    } catch (\Exception $e) { \Illuminate\Support\Facades\Log::error('Mail failed: ' . $e->getMessage()); }
    return redirect()->route('site.contact')->with('contact_success', true);
})->name('site.contact.send');

